def accept_address_transfer(
    address: str,
    *,
    tag_specifications: list[dict[str, Any]] | None = None,
    region_name: str | None = None,
) -> AcceptAddressTransferResult:
    """Accept address transfer.

    Args:
        address: Address.
        tag_specifications: Tag specifications.
        region_name: AWS region override.

    Raises:
        RuntimeError: If the API call fails.
    """
    client = get_client("ec2", region_name)
    kwargs: dict[str, Any] = {}
    kwargs["Address"] = address
    if tag_specifications is not None:
        kwargs["TagSpecifications"] = tag_specifications
    try:
        resp = client.accept_address_transfer(**kwargs)
    except ClientError as exc:
        raise wrap_aws_error(exc, "Failed to accept address transfer") from exc
    return AcceptAddressTransferResult(
        address_transfer=resp.get("AddressTransfer"),
    )


