def export_image(
    disk_image_format: str,
    image_id: str,
    s3_export_location: dict[str, Any],
    *,
    client_token: str | None = None,
    description: str | None = None,
    role_name: str | None = None,
    tag_specifications: list[dict[str, Any]] | None = None,
    region_name: str | None = None,
) -> ExportImageResult:
    """Export image.

    Args:
        disk_image_format: Disk image format.
        image_id: Image id.
        s3_export_location: S3 export location.
        client_token: Client token.
        description: Description.
        role_name: Role name.
        tag_specifications: Tag specifications.
        region_name: AWS region override.

    Raises:
        RuntimeError: If the API call fails.
    """
    client = get_client("ec2", region_name)
    kwargs: dict[str, Any] = {}
    kwargs["DiskImageFormat"] = disk_image_format
    kwargs["ImageId"] = image_id
    kwargs["S3ExportLocation"] = s3_export_location
    if client_token is not None:
        kwargs["ClientToken"] = client_token
    if description is not None:
        kwargs["Description"] = description
    if role_name is not None:
        kwargs["RoleName"] = role_name
    if tag_specifications is not None:
        kwargs["TagSpecifications"] = tag_specifications
    try:
        resp = client.export_image(**kwargs)
    except ClientError as exc:
        raise wrap_aws_error(exc, "Failed to export image") from exc
    return ExportImageResult(
        description=resp.get("Description"),
        disk_image_format=resp.get("DiskImageFormat"),
        export_image_task_id=resp.get("ExportImageTaskId"),
        image_id=resp.get("ImageId"),
        role_name=resp.get("RoleName"),
        progress=resp.get("Progress"),
        s3_export_location=resp.get("S3ExportLocation"),
        status=resp.get("Status"),
        status_message=resp.get("StatusMessage"),
        tags=resp.get("Tags"),
    )


